const [messages, setMessages] = useState([]);
const [newMessage, setNewMessage] = useState('');

const handleSubmit = (e) => {
  e.preventDefault();
  if (newMessage.trim()) {
    setMessages([...messages, { id: Date.now(), text: newMessage }]);
    setNewMessage('');
  }
};

